import {
  Component,
  Prop,
  State,
  Element,
  Watch,
  Event,
  Method,
  EventEmitter,
  h
} from '@stencil/core';
import {
  getHostAttributes,
  getSpreadableAttributes,
  setDefaultHostAttributes,
  setStyleAttribute
} from '@src/utils/kds-utils/attributes/attributeUtils';
import { registerAttributeObserver } from '@src/utils/kds-utils/registerObserver';

interface KdsTextHostElement extends HTMLElement {
  nativeElement: HTMLElement;
}

/**
 * > **Note:** `<kds-text />` is a [primitive web component](primitives/) that accepts all props listed below and any attributes prefixed with `inner-`.
 * `inner-*` attributes are stripped of their `inner-` prefix and placed onto the native element.
 */

@Component({
  tag: 'kds-text',
  shadow: false
})
export class KdsText {
  @Element() hostEl: KdsTextHostElement;
  /** Increases font weight. */
  @Prop() readonly bold?: boolean = false;

  /** Sets font size. */
  @Prop({ mutable: true }) size: 'l' | 'm' | 's' | 'xs' = 'm';

  /** Changes the HTML tag. */
  @Prop() readonly tag: string = 'span';

  /** Sets a class to the rendered text element. */
  @Prop() readonly textClass?: string;

  @State() innerAttrs: any;
  private observer: MutationObserver;
  private nativeElement: HTMLElement;

  private sizeOpts = ['l', 'm', 's', 'xs'];

  /** Emits when the component is loaded. */
  @Event() ready: EventEmitter;

  @Watch('size')
  validateSize(newSize: string) {
    const isOneOfSizes = this.sizeOpts.includes(newSize);
    if (!isOneOfSizes)
      console.error(
        `size: invalid size ${newSize}. Must be one of: ${this.sizeOpts}`
      );
  }

  componentWillLoad() {
    this.validateSize(this.size);
    this.observer = registerAttributeObserver(this);
    this.innerAttrs = getHostAttributes(this.hostEl);
    setDefaultHostAttributes(this.hostEl);
  }

  componentDidLoad() {
    this.observer.observe(this.hostEl, { attributes: true });
    this.ready.emit(this.nativeElement);
    this.hostEl.nativeElement = this.nativeElement;
  }

  disconnectedCallback() {
    this.observer && this.observer.disconnect();
  }

  /**
   * Returns the native `<span>` element used under the hood.
   */

  @Method()
  getNativeElement(): Promise<HTMLElement> {
    return Promise.resolve(this.nativeElement!);
  }

  render() {
    const { bold, size, tag: Tag } = this;

    return (
      <Tag
        {...getSpreadableAttributes(this.innerAttrs)}
        class={{
          [`kds-Text--${size}`]: true,
          'kds-Text--bold': bold,
          [this.textClass]: Boolean(this.textClass)
        }}
        ref={(el: HTMLElement) => {
          this.nativeElement = el;
          setStyleAttribute(el, this.innerAttrs);
        }}
      >
        <slot />
      </Tag>
    );
  }
}
